/**
 * diagnostics_runner.js
 * ─────────────────────
 * Runs ping + DNS diagnostics and writes a formatted report to
 * /tmp/mcp-workspace/network_report.txt
 *
 * Works entirely within the /tmp/mcp-workspace sandbox.
 */

